-- Doc 1: essence
INSERT INTO brand_docs_locales (id, _locale, _parent_id, title, summary, content)
VALUES (
  1,
  'he',
  1,
  'מהות ו-DNA של זוזי',
  'הפילוסופיה, הראייה והערכים שמנחים כל מה שאנחנו עושים',
  $${"root":{"type":"root","children":[{"type":"heading","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"למה ZUZY קיימת","version":1}],"direction":"rtl","format":"","indent":0,"tag":"h2","version":1},{"type":"paragraph","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"ZUZY קמה כדי לגשר בין הצורך העסקי ליעילות וצמיחה, לבין העולם הטכנולוגי שמאפשר זאת. אנחנו קיימים משום שבעלי עסקים קטנים ובינוניים יודעים שהם רוצים יותר סדר, צמיחה ושקט תפעולי – אבל לא יודעים איך לממש זאת מבחינה טכנולוגית.","version":1}],"direction":"rtl","format":"","indent":0,"textFormat":0,"version":1},{"type":"paragraph","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"הרבה עסקים קטנים-בינוניים תקועים עם פתרונות מדף שלא מתאימים בדיוק לצרכיהם, או שהם טובעים במשימות ידניות מבזבזות זמן.","version":1}],"direction":"rtl","format":"","indent":0,"textFormat":0,"version":1},{"type":"paragraph","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"אצלנו הטכנולוגיה היא אמצעי, לא מטרה – אנחנו רותמים אותה לשרת את התהליכים והמטרות הייחודיות של כל עסק, במקום לכפות על העסק להתאים את עצמו לכלים גנריים.","version":1}],"direction":"rtl","format":"","indent":0,"textFormat":0,"version":1},{"type":"heading","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"הפילוסופיה שמנחה אותנו","version":1}],"direction":"rtl","format":"","indent":0,"tag":"h2","version":1},{"type":"paragraph","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"אנו מאמינים שטכנולוגיה ועסקים צריכים לעבוד בהרמוניה. מבחינתנו, עסק לא צריך \"להתכופף\" בשביל תוכנה או מערכת; להפך – הטכנולוגיה צריכה להתאים את עצמה לעסק.","version":1}],"direction":"rtl","format":"","indent":0,"textFormat":0,"version":1},{"type":"paragraph","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"אנחנו רואים בטכנולוגיה כלי לשחרור הפוטנציאל של העסק: אוטומציה של משימות חוזרות, קישור בין מערכות, והנגשת מידע לקבלת החלטות – כל אלו הם אמצעים להשיג תוצאה עסקית ולא רק לשם חידוש טכנולוגי כשלעצמו.","version":1}],"direction":"rtl","format":"","indent":0,"textFormat":0,"version":1},{"type":"paragraph","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"בפילוסופיה שלנו, חדשנות טכנולוגית חשובה רק אם היא מניבה ערך מוחשי לעסק.","version":1}],"direction":"rtl","format":"","indent":0,"textFormat":0,"version":1},{"type":"heading","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"מה ZUZY באמת מוכרת","version":1}],"direction":"rtl","format":"","indent":0,"tag":"h2","version":1},{"type":"paragraph","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"ZUZY לא \"מוכרת טכנולוגיה\" במובן הצר – היא מוכרת שיפור מוחשי בעסק. המוצר האמיתי שלנו הוא התוצאה העסקית: יותר סדר בתהליכים, צמיחה בהכנסות ובכמות הלקוחות, ושקט נפשי בניהול התפעול היומיומי.","version":1}],"direction":"rtl","format":"","indent":0,"textFormat":0,"version":1},{"type":"paragraph","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"הלקוח לא רוצה את הטכנולוגיה לכשעצמה, אלא את הפתרון שהטכנולוגיה מספקת. ZUZY מתמקדת בדיוק ב\"החור\" הזה – בתוצאה הסופית עבור העסק.","version":1}],"direction":"rtl","format":"","indent":0,"textFormat":0,"version":1},{"type":"heading","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"ערכי הליבה","version":1}],"direction":"rtl","format":"","indent":0,"tag":"h2","version":1},{"type":"heading","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"חדשנות פרקטית","version":1}],"direction":"rtl","format":"","indent":0,"tag":"h3","version":1},{"type":"paragraph","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"טכנולוגיה מתקדמת שמשרתת מטרה עסקית ברורה, לא חידוש לשמו","version":1}],"direction":"rtl","format":"","indent":0,"textFormat":0,"version":1},{"type":"heading","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"שותפות אמיתית","version":1}],"direction":"rtl","format":"","indent":0,"tag":"h3","version":1},{"type":"paragraph","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"אנחנו שותפים לדרך, לא ספקים חד-פעמיים. צומחים יחד עם הלקוחות","version":1}],"direction":"rtl","format":"","indent":0,"textFormat":0,"version":1},{"type":"heading","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"אמינות ושקיפות","version":1}],"direction":"rtl","format":"","indent":0,"tag":"h3","version":1},{"type":"paragraph","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"דיבור ברור, מחירים שקופים, הבטחות שאנחנו עומדים מאחוריהן","version":1}],"direction":"rtl","format":"","indent":0,"textFormat":0,"version":1},{"type":"heading","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"פשטות ממוקדת","version":1}],"direction":"rtl","format":"","indent":0,"tag":"h3","version":1},{"type":"paragraph","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"פתרונות נגישים וקלים להבנה, בלי מורכבות מיותרת","version":1}],"direction":"rtl","format":"","indent":0,"textFormat":0,"version":1}],"direction":"rtl","format":"","indent":0,"version":1}}$$::jsonb
);

-- Doc 2: brand-voice
INSERT INTO brand_docs_locales (id, _locale, _parent_id, title, summary, content)
VALUES (
  2,
  'he',
  2,
  'שפה וטון של המותג',
  'DNA המותג – איך מדברים, כותבים ונראים בכל נקודת מגע',
  $${"root":{"type":"root","children":[{"type":"heading","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"עקרונות הטון והשפה","version":1}],"direction":"rtl","format":"","indent":0,"tag":"h2","version":1},{"type":"heading","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"בגובה העיניים, אך מקצועי","version":1}],"direction":"rtl","format":"","indent":0,"tag":"h3","version":1},{"type":"paragraph","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"תקשורת מובנת לבעל עסק שאינו טכנאי, בלי לזלזל באינטליגנציה שלו. נמנעים מז׳רגון טכני כבד ומונחים מעורפלים.","version":1}],"direction":"rtl","format":"","indent":0,"textFormat":0,"version":1},{"type":"heading","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"ממוקד תועלות, לא תכונות","version":1}],"direction":"rtl","format":"","indent":0,"tag":"h3","version":1},{"type":"paragraph","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"מדברים על מה יוצא ללקוח ולא על הטכנולוגיה עצמה. סיפורים והצלחות, לא מפרטים טכניים.","version":1}],"direction":"rtl","format":"","indent":0,"textFormat":0,"version":1},{"type":"heading","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"חד ובוטח","version":1}],"direction":"rtl","format":"","indent":0,"tag":"h3","version":1},{"type":"paragraph","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"כשאומרים משהו – זה ברור ונחרץ. לא מטביעים את המסר בתוך פסקאות מפותלות. הביטחון מעיד על מומחיות.","version":1}],"direction":"rtl","format":"","indent":0,"textFormat":0,"version":1},{"type":"heading","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"אנושי, ידידותי ותומך","version":1}],"direction":"rtl","format":"","indent":0,"tag":"h3","version":1},{"type":"paragraph","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"טון אמפתי ואכפתי. מילים של שותפות (\"בוא נפתור את זה יחד\") במקום מילים מנוכרות.","version":1}],"direction":"rtl","format":"","indent":0,"textFormat":0,"version":1},{"type":"heading","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"חיובי ומעצים","version":1}],"direction":"rtl","format":"","indent":0,"tag":"h3","version":1},{"type":"paragraph","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"מדגישים אפשרויות ולא מגבלות. מילים כמו \"להצליח\", \"לצמוח\", \"לשלוט בעסק שלך\".","version":1}],"direction":"rtl","format":"","indent":0,"textFormat":0,"version":1},{"type":"heading","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"עקבי בכל הערוצים","version":1}],"direction":"rtl","format":"","indent":0,"tag":"h3","version":1},{"type":"paragraph","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"הטון והשפה זהים באתר, ברשתות, במצגות ובאימיילים. מיתוג עקבי בונה אמון.","version":1}],"direction":"rtl","format":"","indent":0,"textFormat":0,"version":1},{"type":"heading","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"דוגמאות לשפה בפועל","version":1}],"direction":"rtl","format":"","indent":0,"tag":"h2","version":1},{"type":"heading","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"כותרת עמוד באתר","version":1}],"direction":"rtl","format":"","indent":0,"tag":"h3","version":1},{"type":"paragraph","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"\"פחות בלגן, יותר צמיחה. הטכנולוגיה עושה עבורך את העבודה.\"","version":1}],"direction":"rtl","format":"","indent":0,"textFormat":0,"version":1},{"type":"heading","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"תוכן \"למה ZUZY\" באתר","version":1}],"direction":"rtl","format":"","indent":0,"tag":"h3","version":1},{"type":"paragraph","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"\"אנחנו ב-ZUZY יודעים איך זה מרגיש כשהעסק גדל והכאוס חוגג. בדיוק בגלל זה בנינו פתרונות שעושים סדר בבלאגן, ומפנים לך זמן להגדיל את העסק.\"","version":1}],"direction":"rtl","format":"","indent":0,"textFormat":0,"version":1},{"type":"heading","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"מילות מפתח של המותג","version":1}],"direction":"rtl","format":"","indent":0,"tag":"h2","version":1},{"type":"paragraph","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"סדר • שקט • צמיחה • פשטות • שותפות • תוצאות • יעילות • אוטומציה • התאמה • ליווי","version":1}],"direction":"rtl","format":"","indent":0,"textFormat":0,"version":1}],"direction":"rtl","format":"","indent":0,"version":1}}$$::jsonb
);

-- Doc 3: differentiation
INSERT INTO brand_docs_locales (id, _locale, _parent_id, title, summary, content)
VALUES (
  3,
  'he',
  3,
  'בידול ומיצוב',
  'מה מבדיל אותנו מכלי אוטומציה, סוכנויות טכנולוגיה, יועצים ו-CRM מדף',
  $${"root":{"type":"root","children":[{"type":"heading","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"הגישה ההיברידית","version":1}],"direction":"rtl","format":"","indent":0,"tag":"h2","version":1},{"type":"paragraph","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"ZUZY מבדלת את עצמה באמצעות שילוב ייחודי של פתרונות \"מדף\" מוכנים יחד עם פיתוח מותאם אישית","version":1}],"direction":"rtl","format":"","indent":0,"textFormat":0,"version":1},{"type":"heading","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"כלי אוטומציה ו-CRM מדף","version":1}],"direction":"rtl","format":"","indent":0,"tag":"h2","version":1},{"type":"paragraph","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"Zapier, Monday, HubSpot וכו׳. הבעיות: מחייבים את העסק להתאים את עצמו לכלי, נכשלים כשהעסק גדל או יש תהליכים יוצאי דופן, חברות מנצלות רק 10%-15% מהפונקציונליות.","version":1}],"direction":"rtl","format":"","indent":0,"textFormat":0,"version":1},{"type":"paragraph","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"הפתרון של ZUZY: מתאימים את הפתרון לתהליכים של הלקוח – במקום שהלקוח יתכופף לתכתיבי התוכנה.","version":1}],"direction":"rtl","format":"","indent":0,"textFormat":0,"version":1},{"type":"heading","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"סוכנויות פיתוח טכנולוגי","version":1}],"direction":"rtl","format":"","indent":0,"tag":"h2","version":1},{"type":"paragraph","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"הבעיות: מתחילות מדף חלק – זמן רב ועלויות גבוהות, מקבלות אפיון ומוסרות מוצר – ללא הבנה עסקית, מסיימות בנקודת המסירה – אין ליווי.","version":1}],"direction":"rtl","format":"","indent":0,"textFormat":0,"version":1},{"type":"paragraph","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"הפתרון של ZUZY: מגיעים עם \"ארגז כלים\" של רכיבים מוכנים מניסיון עבר. חיסכון של עד 40% בזמן ההטמעה. ליווי גם אחרי ההשקה.","version":1}],"direction":"rtl","format":"","indent":0,"textFormat":0,"version":1},{"type":"heading","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"יועצים טכניים ועסקיים","version":1}],"direction":"rtl","format":"","indent":0,"tag":"h2","version":1},{"type":"paragraph","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"הבעיות: נותנים המלצות ודוחות – לא תוצאות, משאירים את הלקוח להתמודד לבד, מוכרים שעות ייעוץ לא תוצר סופי.","version":1}],"direction":"rtl","format":"","indent":0,"textFormat":0,"version":1},{"type":"paragraph","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"הפתרון של ZUZY: מתחילים כמו יועצים באבחון ואסטרטגיה, אך ממשיכים לפיתוח והטמעה בפועל. נמדדים על התוצאה העסקית.","version":1}],"direction":"rtl","format":"","indent":0,"textFormat":0,"version":1},{"type":"heading","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"לסיכום: מה מבדיל את ZUZY","version":1}],"direction":"rtl","format":"","indent":0,"tag":"h2","version":1},{"type":"paragraph","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"בשוק רווי פתרונות חלקיים – ZUZY מציעה פתרון הוליסטי. גם מוח (ידע לייעץ ולתכנן), גם ידיים (גמישות לפתח פתרון מותאם), וגם לב (מחויבות ללוות לאורך זמן).","version":1}],"direction":"rtl","format":"","indent":0,"textFormat":0,"version":1}],"direction":"rtl","format":"","indent":0,"version":1}}$$::jsonb
);

