  4,
  'מודל עסקי',
  'הכנסות, סוגי מוצרים, מחירים, ותמהיל מדף מול תפירה',
  $${"root":{"type":"root","children":[{"type":"heading","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"מקורות הכנסה","version":1}],"direction":"rtl","format":"","indent":0,"tag":"h2","version":1},{"type":"heading","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"פרויקטי פיתוח מותאמים","version":1}],"direction":"rtl","format":"","indent":0,"tag":"h3","version":1},{"type":"paragraph","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"תמחור לפי חבילה או שעות עבור פיתוח ויישום פתרון התפור לצרכי הלקוח","version":1}],"direction":"rtl","format":"","indent":0,"textFormat":0,"version":1},{"type":"heading","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"רישיונות ומנויים למודולים","version":1}],"direction":"rtl","format":"","indent":0,"tag":"h3","version":1},{"type":"paragraph","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"\"אפליקציות מדף\" או רכיבים מוכנים שנמכרים במנוי חודשי – הכנסה חוזרת","version":1}],"direction":"rtl","format":"","indent":0,"textFormat":0,"version":1},{"type":"heading","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"תחזוקה ושדרוגים","version":1}],"direction":"rtl","format":"","indent":0,"tag":"h3","version":1},{"type":"paragraph","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"הסכם תחזוקה, תמיכה ושיפור מתמשך בדמי שירות חודשיים או בנק שעות","version":1}],"direction":"rtl","format":"","indent":0,"textFormat":0,"version":1},{"type":"heading","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"סוגי המוצרים","version":1}],"direction":"rtl","format":"","indent":0,"tag":"h2","version":1},{"type":"heading","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"פתרונות מדף חוצי-תעשייה","version":1}],"direction":"rtl","format":"","indent":0,"tag":"h3","version":1},{"type":"paragraph","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"פתרונות שפיתחנו כמענה לצורך שחוזר אצל עסקים רבים. מתומחרים בצורה נגישה כדי להוריד חסמי כניסה.","version":1}],"direction":"rtl","format":"","indent":0,"textFormat":0,"version":1},{"type":"heading","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"פתרונות מותאמים אישית","version":1}],"direction":"rtl","format":"","indent":0,"tag":"h3","version":1},{"type":"paragraph","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"תמחור פרימיום בהתאם להיקף הפיתוח. גם כאן משלבים רכיבים קיימים לצמצום עלויות. עד 40% חיסכון בזמן הטמעה.","version":1}],"direction":"rtl","format":"","indent":0,"textFormat":0,"version":1},{"type":"heading","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"תמהיל מדף מול תפירה","version":1}],"direction":"rtl","format":"","indent":0,"tag":"h2","version":1},{"type":"paragraph","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"האסטרטגיה העסקית שואפת לאיזון בין פתרונות מוכנים למותאמים. בשאיפה, כ-50% מההכנסות יגיעו ממוצרים סטנדרטיים חוזרים – המודולים והרישיונות – כי הם סקיילביליים במיוחד.","version":1}],"direction":"rtl","format":"","indent":0,"textFormat":0,"version":1},{"type":"heading","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"הסימביוזה בין מוצרים לפרויקטים","version":1}],"direction":"rtl","format":"","indent":0,"tag":"h2","version":1},{"type":"paragraph","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"כל פרויקט מותאם שאנחנו מבצעים מלמד אותנו משהו חדש ומוליד לעיתים רכיב חדש שנוכל להפוך למודול מדף בעתיד.","version":1}],"direction":"rtl","format":"","indent":0,"textFormat":0,"version":1},{"type":"heading","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"גמישות ללקוח","version":1}],"direction":"rtl","format":"","indent":0,"tag":"h2","version":1},{"type":"paragraph","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"במודל העסקי שלנו יש גמישות ללקוח לבחור: הוא יכול להתחיל מפתרון מדף פשוט וזול ככניסה ראשונית, וכאשר הוא גדל או מזהה צורך מיוחד – להוסיף רכיב מותאם.","version":1}],"direction":"rtl","format":"","indent":0,"textFormat":0,"version":1}],"direction":"rtl","format":"","indent":0,"version":1}}$$::jsonb
);

-- Doc 5: solutions
INSERT INTO brand_docs_locales (id, _locale, _parent_id, title, summary, content)
VALUES (
  5,
  'he',
  5,
  'פתרונות ושירותים',
  'ארבע קטגוריות פתרונות שמכסות את כל הצרכים הטכנולוגיים של העסק',
  $${"root":{"type":"root","children":[{"type":"heading","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"הצעת הערך העיקרית","version":1}],"direction":"rtl","format":"","indent":0,"tag":"h2","version":1},{"type":"paragraph","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"ZUZY מציעה לעסקים קטנים-בינוניים שירות מקצה לקצה להפיכת התפעול לטכנולוגי, חכם ויעיל יותר. במקום שהלקוח יצטרך לרכוש עשרה כלים שונים ולנסות לגרום להם לעבוד יחד – הוא מקבל פתרון אחד אינטגרטיבי.","version":1}],"direction":"rtl","format":"","indent":0,"textFormat":0,"version":1},{"type":"heading","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"סדר וייעול תהליכים פנימיים","version":1}],"direction":"rtl","format":"","indent":0,"tag":"h2","version":1},{"type":"paragraph","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"אוטומציה של תהליכים וייעול תפעול. הפתרונות מתמקדים בהורדת העומס מהצוות על ידי החלפת עבודה ידנית ברצף אוטומטי.","version":1}],"direction":"rtl","format":"","indent":0,"textFormat":0,"version":1},{"type":"heading","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"צמיחה וניהול לקוחות","version":1}],"direction":"rtl","format":"","indent":0,"tag":"h2","version":1},{"type":"paragraph","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"פתרונות שדוחפים צמיחה כי הם מאפשרים לטפל ביותר לקוחות ובצורה איכותית, ללא צורך להגדיל באותה מידה את כוח האדם. CRM מותאם, שיווק אוטומטי, צ׳אטבוט ומשפך מכירה.","version":1}],"direction":"rtl","format":"","indent":0,"textFormat":0,"version":1},{"type":"heading","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"אינטגרציה ומידע","version":1}],"direction":"rtl","format":"","indent":0,"tag":"h2","version":1},{"type":"paragraph","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"חיבור מערכות וזרימת מידע חלקה. העסק יודע מה קורה בכל רגע, ויכול לקבל החלטות מבוססות נתונים בקלות. דשבורדים, BI, סנכרון מערכות.","version":1}],"direction":"rtl","format":"","indent":0,"textFormat":0,"version":1},{"type":"heading","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"פתרונות תפורים ייחודיים","version":1}],"direction":"rtl","format":"","indent":0,"tag":"h2","version":1},{"type":"paragraph","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"מקרים שבהם עסק נתקל בבעיה ספציפית מאוד ואין לה פתרון בשוק. \"תתאר לנו את החלום או את הכאב שלך, ונמציא לך פתרון.\"","version":1}],"direction":"rtl","format":"","indent":0,"textFormat":0,"version":1},{"type":"paragraph","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"השירות של ZUZY הוא מודולרי וגמיש – הלקוח לא חייב לקחת את כל החבילה.","version":1}],"direction":"rtl","format":"","indent":0,"textFormat":0,"version":1}],"direction":"rtl","format":"","indent":0,"version":1}}$$::jsonb
);

-- Doc 6: sales
INSERT INTO brand_docs_locales (id, _locale, _parent_id, title, summary, content)
VALUES (
  6,
  'he',
  6,
  'אסטרטגיית מכירה',
  'מי הלקוח הראשוני, איך מתחילים למכור, ואיך מוכיחים ערך מהר',
  $${"root":{"type":"root","children":[{"type":"heading","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"הלקוח האידיאלי","version":1}],"direction":"rtl","format":"","indent":0,"tag":"h2","version":1},{"type":"paragraph","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"בעלי עסקים קטנים-בינוניים שמרגישים את ה\"כאב\" באופן הכי חד. עסק עם 10-50 עובדים שנמצא בצמיחה אבל חווה בלגן תפעולי.","version":1}],"direction":"rtl","format":"","indent":0,"textFormat":0,"version":1},{"type":"heading","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"אסטרטגיית חדירה","version":1}],"direction":"rtl","format":"","indent":0,"tag":"h2","version":1},{"type":"paragraph","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"הפוקוס הראשוני במכירות יהיה על הסרת חסמי כניסה ובניית אמון מהיר. עסקים קטנים רגישים למחיר ולסיכונים.","version":1}],"direction":"rtl","format":"","indent":0,"textFormat":0,"version":1},{"type":"heading","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"אבחון טכנולוגי חינמי","version":1}],"direction":"rtl","format":"","indent":0,"tag":"h3","version":1},{"type":"paragraph","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"פגישה של שעה-שעתיים ללמוד את העסק, עם דוח ממצאים ראשוני.","version":1}],"direction":"rtl","format":"","indent":0,"textFormat":0,"version":1},{"type":"heading","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"פתרון ממוקד בעיה אחת","version":1}],"direction":"rtl","format":"","indent":0,"tag":"h3","version":1},{"type":"paragraph","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"במקום למכור את כל החבילה – מתחילים מהבעיה הכואבת ביותר.","version":1}],"direction":"rtl","format":"","indent":0,"textFormat":0,"version":1},{"type":"heading","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"מחירים שקופים ופשוטים","version":1}],"direction":"rtl","format":"","indent":0,"tag":"h3","version":1},{"type":"paragraph","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"בלי חוזים ארוכי טווח, בלי עלויות נסתרות, אפשרות לבטל בכל עת.","version":1}],"direction":"rtl","format":"","indent":0,"textFormat":0,"version":1},{"type":"heading","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"הוכחת ערך מהירה","version":1}],"direction":"rtl","format":"","indent":0,"tag":"h2","version":1},{"type":"paragraph","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"לעסקים קטנים יש מעט סבלנות ונמוך סובלנות לסיכונים. האסטרטגיה שלנו היא לפרוס את הפתרון באופן שנותן \"ניצחון מהיר\". יעד: כל לקוח חדש צריך להגיע ל-\"רגע ניצחון\" תוך 30-60 יום.","version":1}],"direction":"rtl","format":"","indent":0,"textFormat":0,"version":1},{"type":"heading","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"בניית אמון","version":1}],"direction":"rtl","format":"","indent":0,"tag":"h2","version":1},{"type":"paragraph","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"עסקים קטנים לרוב מושקעים אישית בעסק ולכן רגישים. על ידי כך שנהיה שותף אמיתי עבורם מהיום הראשון, ניצור אמון. נעבוד בפשטות ובשקיפות.","version":1}],"direction":"rtl","format":"","indent":0,"textFormat":0,"version":1}],"direction":"rtl","format":"","indent":0,"version":1}}$$::jsonb
);

-- Doc 7: process
INSERT INTO brand_docs_locales (id, _locale, _parent_id, title, summary, content)
VALUES (
  7,
  'he',
  7,
  'תהליך עבודה',
  'חמישה שלבים מתודולוגיים שמבטיחים תוצאה איכותית',
  $${"root":{"type":"root","children":[{"type":"heading","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"שלב 1 – אבחון וניתוח ראשוני","version":1}],"direction":"rtl","format":"","indent":0,"tag":"h2","version":1},{"type":"paragraph","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"צוות ZUZY מקיים פגישות עם בעלי העסק ובעלי תפקידים מרכזיים. שואלים, מקשיבים ומתצפתים. מה בודקים: תהליכים קיימים, נקודות כאב, כלים בשימוש. תוצר: מסמך אפיון ראשוני ותכנית עבודה מוצעת.","version":1}],"direction":"rtl","format":"","indent":0,"textFormat":0,"version":1},{"type":"heading","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"שלב 2 – תכנון מפורט ועיצוב הפתרון","version":1}],"direction":"rtl","format":"","indent":0,"tag":"h2","version":1},{"type":"paragraph","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"צלילה לאפיון מפורט של המערכת או הפתרון. שרטוט תהליכי עבודה חדשים, הגדרת פונקציות ותכונות, ותכנון ארכיטקטורה. תוצר: מסמך אפיון מלא + תכנית פרויקט סופית עם מיילסטונס.","version":1}],"direction":"rtl","format":"","indent":0,"textFormat":0,"version":1},{"type":"heading","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"שלב 3 – פיתוח והטמעה","version":1}],"direction":"rtl","format":"","indent":0,"tag":"h2","version":1},{"type":"paragraph","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"המפתחים מתחילים לעבוד לפי האפיון: כתיבת קוד למודולים ייחודיים, התאמת מודולים קיימים. עובדים ב-Agile עם הדגמות תכופות. תוצר: מערכת פועלת מוכנה לבדיקות.","version":1}],"direction":"rtl","format":"","indent":0,"textFormat":0,"version":1},{"type":"heading","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"שלב 4 – בדיקות, הדרכה והשקה","version":1}],"direction":"rtl","format":"","indent":0,"tag":"h2","version":1},{"type":"paragraph","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"שלב בדיקות קפדני, הרצה מבוקרת עם קבוצת משתמשי מפתח, והדרכות לצוות של הלקוח. רק כשהכל מוכן – השקה רחבה. תוצר: מערכת חיה באוויר + צוות מאומן.","version":1}],"direction":"rtl","format":"","indent":0,"textFormat":0,"version":1},{"type":"heading","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"שלב 5 – ליווי, תחזוקה ושיפור מתמשך","version":1}],"direction":"rtl","format":"","indent":0,"tag":"h2","version":1},{"type":"paragraph","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"המסירה היא רק ההתחלה. ליווי מתמשך לפחות בחודשים הראשונים, מסלול תחזוקה עם עדכונים תקופתיים, מדידות הצלחה אל מול היעדים. שותפות ארוכת טווח – המערכות מתעדכנות עם צמיחת העסק.","version":1}],"direction":"rtl","format":"","indent":0,"textFormat":0,"version":1}],"direction":"rtl","format":"","indent":0,"version":1}}$$::jsonb
);

-- Doc 8: faq
INSERT INTO brand_docs_locales (id, _locale, _parent_id, title, summary, content)
VALUES (
  8,
  'he',
  8,
  'שאלות ותשובות',
  'תשובות לשאלות הנפוצות ביותר על ZUZY',
  $${"root":{"type":"root","children":[{"type":"heading","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"מה זה ZUZY?","version":1}],"direction":"rtl","format":"","indent":0,"tag":"h2","version":1},{"type":"paragraph","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"ZUZY היא שירות להטמעת טכנולוגיה ו-AI בעסקים קטנים ובינוניים. אנחנו עוזרים לעסקים לעבור מתפעול ידני לתפעול חכם ודיגיטלי.","version":1}],"direction":"rtl","format":"","indent":0,"textFormat":0,"version":1},{"type":"heading","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"למי ZUZY מתאים?","version":1}],"direction":"rtl","format":"","indent":0,"tag":"h2","version":1},{"type":"paragraph","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"ZUZY מתאים לעסקים קטנים ובינוניים (5-50 עובדים) שרוצים לשפר יעילות תפעולית, לחסוך זמן בעבודה ידנית, להטמיע כלים דיגיטליים ולהשתמש ב-AI בצורה פרקטית.","version":1}],"direction":"rtl","format":"","indent":0,"textFormat":0,"version":1},{"type":"heading","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"כמה עולה השירות?","version":1}],"direction":"rtl","format":"","indent":0,"tag":"h2","version":1},{"type":"paragraph","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"המחירים משתנים לפי היקף העבודה: אבחון ראשוני 2,500-5,000 ש\"ח, פרויקט הטמעה 8,000-25,000 ש\"ח, ריטיינר חודשי 2,000-6,000 ש\"ח.","version":1}],"direction":"rtl","format":"","indent":0,"textFormat":0,"version":1},{"type":"heading","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"כמה זמן לוקח פרויקט?","version":1}],"direction":"rtl","format":"","indent":0,"tag":"h2","version":1},{"type":"paragraph","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"אבחון: 1-2 שבועות, הטמעה בסיסית: 2-4 שבועות, פרויקט מלא: 1-3 חודשים.","version":1}],"direction":"rtl","format":"","indent":0,"textFormat":0,"version":1},{"type":"heading","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"מה כולל שירות ההטמעה?","version":1}],"direction":"rtl","format":"","indent":0,"tag":"h2","version":1},{"type":"paragraph","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"אבחון צרכים ומיפוי תהליכים, בחירת כלים מתאימים, הקמה והגדרה, הדרכת צוות, ותמיכה שוטפת.","version":1}],"direction":"rtl","format":"","indent":0,"textFormat":0,"version":1},{"type":"heading","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"מה הבידול של ZUZY?","version":1}],"direction":"rtl","format":"","indent":0,"tag":"h2","version":1},{"type":"paragraph","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"ליווי אישי ולא רק הטמעה טכנית, התאמה לצרכים העסקיים, מיקוד ב-ROI מהיר, עבודה עם עסקים קטנים-בינוניים בלבד.","version":1}],"direction":"rtl","format":"","indent":0,"textFormat":0,"version":1},{"type":"heading","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"איך מתחילים?","version":1}],"direction":"rtl","format":"","indent":0,"tag":"h2","version":1},{"type":"paragraph","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"יצירת קשר דרך האתר, שיחת היכרות חינם, הצעת מחיר לאבחון, ותחילת עבודה.","version":1}],"direction":"rtl","format":"","indent":0,"textFormat":0,"version":1},{"type":"heading","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"האם יש התחייבות?","version":1}],"direction":"rtl","format":"","indent":0,"tag":"h2","version":1},{"type":"paragraph","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"אין התחייבות לטווח ארוך. כל פרויקט נמדד בנפרד.","version":1}],"direction":"rtl","format":"","indent":0,"textFormat":0,"version":1}],"direction":"rtl","format":"","indent":0,"version":1}}$$::jsonb
);

-- Doc 9: case-studies
INSERT INTO brand_docs_locales (id, _locale, _parent_id, title, summary, content)
VALUES (
  9,
  'he',
  9,
  'מקרי בוחן',
  'דוגמאות לפרויקטים שביצענו ותוצאות שהשגנו',
  $${"root":{"type":"root","children":[{"type":"heading","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"משרד עורכי דין","version":1}],"direction":"rtl","format":"","indent":0,"tag":"h2","version":1},{"type":"paragraph","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"הבעיה: ניהול לקוחות ותיקים בטבלאות אקסל, שכחת משימות, קושי במעקב תשלומים. הפתרון: הטמעת Monday CRM + אוטומציות לתזכורות + חיבור לחשבוניות. התוצאה: חיסכון של 10 שעות שבועיות, ירידה ב-80% באיחורי תשלום.","version":1}],"direction":"rtl","format":"","indent":0,"textFormat":0,"version":1},{"type":"heading","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"חברת שיפוצים","version":1}],"direction":"rtl","format":"","indent":0,"tag":"h2","version":1},{"type":"paragraph","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"הבעיה: הצעות מחיר ידניות, אובדן לידים, חוסר מעקב פרויקטים. הפתרון: מערכת הצעות מחיר אוטומטית + CRM לניהול לידים + לוח פרויקטים. התוצאה: 40% יותר סגירות, זמן הצעת מחיר ירד מ-2 ימים ל-2 שעות.","version":1}],"direction":"rtl","format":"","indent":0,"textFormat":0,"version":1},{"type":"heading","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"קליניקה פרטית","version":1}],"direction":"rtl","format":"","indent":0,"tag":"h2","version":1},{"type":"paragraph","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"הבעיה: זימון תורים בטלפון, תזכורות ידניות, ניהול מסמכים בנייר. הפתרון: מערכת זימון אונליין + תזכורות SMS אוטומטיות + דיגיטציה של מסמכים. התוצאה: 60% פחות שיחות טלפון, ירידה ב-90% באי-הגעות.","version":1}],"direction":"rtl","format":"","indent":0,"textFormat":0,"version":1},{"type":"heading","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"סוכנות ביטוח","version":1}],"direction":"rtl","format":"","indent":0,"tag":"h2","version":1},{"type":"paragraph","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"הבעיה: מעקב חידושי פוליסות ידני, שכחת לקוחות, דוחות ידניים. הפתרון: אוטומציות לתזכורות חידוש + דשבורד BI + צ׳אטבוט לשאלות נפוצות. התוצאה: 25% יותר חידושים, חיסכון של 15 שעות שבועיות.","version":1}],"direction":"rtl","format":"","indent":0,"textFormat":0,"version":1},{"type":"heading","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"חנות אונליין","version":1}],"direction":"rtl","format":"","indent":0,"tag":"h2","version":1},{"type":"paragraph","children":[{"type":"text","detail":0,"format":0,"mode":"normal","style":"","text":"הבעיה: ניהול מלאי ידני, תשובות ידניות לשאלות לקוחות, חוסר סנכרון בין ערוצים. הפתרון: אינטגרציה בין האתר ל-ERP + צ׳אטבוט AI לשירות לקוחות + דשבורד מכירות. התוצאה: 30% פחות מלאי תקוע, 50% פחות פניות לשירות לקוחות.","version":1}],"direction":"rtl","format":"","indent":0,"textFormat":0,"version":1}],"direction":"rtl","format":"","indent":0,"version":1}}$$::jsonb
);

